// Turn-based combat: player attacks, enemy responds. Enemy taunts are
// generated by Groq. XP, gold and loot awards go through the server.

import { api, streamNpcReply } from './api.js';
import { equipmentBonuses } from './items.js';

const randBetween = (min, max) => min + Math.floor(Math.random() * (max - min + 1));

export class CombatManager {
  constructor(game) {
    this.game = game;
    this.enemy = null;
    this.busy = false;
    this.over = false; // fight resolved, waiting for the panel to close

    this.panel = document.getElementById('combat-panel');
    this.log = document.getElementById('combat-log');
    this.playerName = document.getElementById('combat-player-name');
    this.enemyName = document.getElementById('combat-enemy-name');
    this.playerHpBar = document.getElementById('combat-player-hp');
    this.enemyHpBar = document.getElementById('combat-enemy-hp');
    this.attackBtn = document.getElementById('btn-attack');
    this.fleeBtn = document.getElementById('btn-flee');

    this.attackBtn.addEventListener('click', () => this.playerAttack());
    this.fleeBtn.addEventListener('click', () => this.flee());
  }

  get active() { return this.enemy !== null; }

  start(npcInstance) {
    this.enemy = npcInstance;
    this.over = false;
    this.log.innerHTML = '';
    this.playerName.textContent = this.game.player.username;
    this.enemyName.textContent = npcInstance.def.name;
    this.panel.classList.remove('hidden');
    this.setButtons(true);
    this.updateBars();
    this.addLog(`You square up against the ${npcInstance.def.name}!`, 'info');
    this.requestTaunt(`The adventurer ${this.game.player.username} draws a weapon and attacks you!`);
  }

  end() {
    this.enemy = null;
    this.panel.classList.add('hidden');
  }

  setButtons(enabled) {
    this.busy = !enabled;
    this.attackBtn.disabled = !enabled;
    this.fleeBtn.disabled = !enabled;
  }

  addLog(text, kind = '') {
    const line = document.createElement('div');
    if (kind) line.className = kind;
    line.textContent = text;
    this.log.appendChild(line);
    this.log.scrollTop = this.log.scrollHeight;
    return line;
  }

  updateBars() {
    const { stats } = this.game;
    const enemyMax = this.enemy?.def.stats.hp || 1;
    this.playerHpBar.style.width = `${Math.max(0, (stats.hp / stats.max_hp) * 100)}%`;
    this.enemyHpBar.style.width = `${Math.max(0, ((this.enemy?.hp || 0) / enemyMax) * 100)}%`;
    this.game.ui.updateHud();
  }

  // One short Groq-generated taunt, streamed into the combat log.
  requestTaunt(situation) {
    const { stats } = this.game;
    const line = this.addLog(`${this.enemy.def.name}: `, 'taunt');
    const enemy = this.enemy;
    streamNpcReply(
      {
        npcId: enemy.def.id,
        playerMessage: `${situation} Shout a single short taunt (one sentence, stay in character).`,
        playerStats: { level: stats.level, gold: stats.gold }
      },
      (text) => {
        line.textContent += text;
        this.log.scrollTop = this.log.scrollHeight;
      }
    ).catch(() => {
      line.textContent += '…growls menacingly.';
    });
  }

  playerTotals() {
    const bonus = equipmentBonuses(this.game.items);
    return {
      attack: this.game.stats.attack + bonus.attack,
      defence: this.game.stats.defence + bonus.defence
    };
  }

  async playerAttack() {
    if (!this.active || this.busy || this.over) return;
    this.setButtons(false);

    const enemyStats = this.enemy.def.stats;
    const damage = Math.max(1, this.playerTotals().attack - enemyStats.defence + randBetween(-2, 2));
    this.enemy.hp = Math.max(0, this.enemy.hp - damage);
    this.addLog(`You hit the ${this.enemy.def.name} for ${damage} damage.`);
    this.updateBars();

    if (this.enemy.hp <= 0) {
      await this.victory();
      return;
    }

    await new Promise((r) => setTimeout(r, 550));
    await this.enemyAttack();
    if (this.active && !this.over) this.setButtons(true);
  }

  async enemyAttack() {
    if (!this.active) return;
    const enemyStats = this.enemy.def.stats;
    const damage = Math.max(1, enemyStats.attack - this.playerTotals().defence + randBetween(-2, 2));
    this.game.stats.hp = Math.max(0, this.game.stats.hp - damage);
    this.addLog(`The ${this.enemy.def.name} hits you for ${damage} damage.`, 'hit');
    this.updateBars();

    if (this.game.stats.hp <= 0) {
      await this.defeat();
      return;
    }
    if (Math.random() < 0.3) {
      this.requestTaunt('You just landed a hit on the player.');
    }
  }

  async victory() {
    const enemy = this.enemy;
    const { xpReward, goldDrop } = enemy.def.stats;
    this.over = true;
    enemy.kill();
    this.addLog(`💀 The ${enemy.def.name} collapses!`, 'info');

    try {
      // XP first — the server resolves level-ups.
      const { stats, levelsGained } = await api.awardXp(xpReward);
      this.game.stats = stats;
      this.game.ui.toast(`+${xpReward} XP`, 'good');
      if (levelsGained > 0) {
        this.game.ui.toast(`⭐ Level up! You are now level ${stats.level}`, 'good');
      }

      const gold = randBetween(goldDrop[0], goldDrop[1]);
      if (gold > 0) {
        const { stats: withGold } = await api.addGold(gold);
        this.game.stats = withGold;
        this.game.ui.toast(`+${gold} gold`, 'good');
      }

      await this.rollLoot();
      await api.setHp(this.game.stats.hp);
    } catch (err) {
      this.game.ui.toast(err.message, 'bad');
    }

    this.game.ui.updateHud();
    setTimeout(() => this.end(), 900);
  }

  async rollLoot() {
    const roll = Math.random();
    let drop = null;
    if (roll < 0.3) {
      drop = { item_name: 'Health Potion', item_type: 'consumable', stats: { heal: 30 } };
    } else if (roll < 0.5) {
      drop = { item_name: 'Goblin Ear', item_type: 'misc' };
    } else if (roll < 0.58) {
      drop = { item_name: 'Rusty Dagger', item_type: 'weapon', slot: 'mainhand', stats: { attack: 3 } };
    }
    if (!drop) return;
    await api.addItem(drop);
    await this.game.refreshInventory();
    this.game.ui.toast(`Loot: ${drop.item_name}`, 'good');
  }

  async defeat() {
    this.over = true;
    this.addLog('☠️ You collapse…', 'hit');
    const { stats, player, world } = this.game;
    stats.hp = Math.ceil(stats.max_hp / 2);
    player.teleport(world.spawn.x, world.spawn.y);
    try {
      await api.setHp(stats.hp);
    } catch { /* will re-sync on next update */ }
    this.game.ui.toast('You were defeated and wake up back in the village.', 'bad');
    this.game.ui.updateHud();
    setTimeout(() => this.end(), 900);
  }

  async flee() {
    if (!this.active || this.busy || this.over) return;
    this.setButtons(false);
    this.addLog('You turn and run!', 'info');
    // Fleeing gives the enemy one free swing.
    await this.enemyAttack();
    if (this.active && !this.over) {
      try { await api.setHp(this.game.stats.hp); } catch { /* ignore */ }
      this.end();
    }
  }
}
